//! Runtime message validation against a [`DataDictionary`].

use truefix_core::{Field, GroupSpec, Message};

use crate::model::{DataDictionary, RejectReason, ValidationError, ValidationOptions};

impl GroupSpec for DataDictionary {
    fn group_of(&self, count_tag: u32) -> Option<(u32, &[u32])> {
        self.groups
            .get(&count_tag)
            .map(|g| (g.delimiter, g.members.as_slice()))
    }
}

/// The first user-defined-field tag (UDFs occupy 5000â€“9999 in FIX).
const UDF_START: u32 = 5000;

impl DataDictionary {
    /// Validate `message` against this dictionary using `opts`.
    ///
    /// Returns the first failure found. Field-membership/format/required failures are
    /// session-level rejects; an unknown-but-structural MsgType is a business-level reject
    /// (FR-C4 two rejection layers).
    pub fn validate(
        &self,
        message: &Message,
        opts: &ValidationOptions,
    ) -> Result<(), ValidationError> {
        let msg_type = message.msg_type().ok_or_else(|| {
            ValidationError::session(RejectReason::InvalidMsgType, Some(35), "missing MsgType")
        })?;
        let mdef = self.message(msg_type).ok_or_else(|| {
            ValidationError::business(
                RejectReason::InvalidMsgType,
                Some(35),
                "MsgType not defined in dictionary",
            )
        })?;

        let mut seen_once: std::collections::BTreeSet<u32> = std::collections::BTreeSet::new();

        for field in message
            .header
            .fields()
            .chain(message.body.fields())
            .chain(message.trailer.fields())
        {
            let tag = field.tag();

            // Tags that are members of a repeating group legitimately repeat once per entry; only
            // flag a repeat for tags that are not part of any group in this message.
            if opts.check_repeated_tags
                && !mdef.member_tags.contains(&tag)
                && !seen_once.insert(tag)
            {
                return Err(ValidationError::session(
                    RejectReason::TagAppearsMoreThanOnce,
                    Some(tag),
                    "tag appears more than once",
                ));
            }

            if opts.validate_fields_have_values && field.value_bytes().is_empty() {
                return Err(ValidationError::session(
                    RejectReason::TagSpecifiedWithoutValue,
                    Some(tag),
                    "field has no value",
                ));
            }

            match self.field(tag) {
                None => {
                    let is_udf = tag >= UDF_START;
                    if is_udf && !opts.validate_user_defined_fields {
                        continue;
                    }
                    if opts.allow_unknown_msg_fields {
                        continue;
                    }
                    return Err(ValidationError::session(
                        RejectReason::InvalidTagNumber,
                        Some(tag),
                        "tag not defined in dictionary",
                    ));
                }
                Some(fdef) => {
                    if opts.check_field_types {
                        if !fdef.field_type.value_ok(field) {
                            return Err(ValidationError::session(
                                RejectReason::IncorrectDataFormat,
                                Some(tag),
                                "value has incorrect data format",
                            ));
                        }
                        if let Ok(value) = field.as_str() {
                            if !fdef.allows(value) {
                                return Err(ValidationError::session(
                                    RejectReason::ValueIsIncorrect,
                                    Some(tag),
                                    "value is not an allowed enumeration",
                                ));
                            }
                        }
                    }

                    let belongs =
                        self.is_header(tag) || self.is_trailer(tag) || mdef.contains_member(tag);
                    if !belongs && !opts.allow_unknown_msg_fields {
                        return Err(ValidationError::session(
                            RejectReason::TagNotDefinedForMessageType,
                            Some(tag),
                            "tag not defined for this message type",
                        ));
                    }
                }
            }
        }

        if opts.check_groups {
            self.validate_groups(message, opts)?;
        }

        if opts.check_required_fields {
            for &tag in &mdef.required {
                if !present(message, tag) {
                    return Err(ValidationError::session(
                        RejectReason::RequiredTagMissing,
                        Some(tag),
                        "required field missing",
                    ));
                }
            }
        }

        Ok(())
    }

    /// Validate repeating-group structure in the (flat, wire-ordered) message body: the NoXxx count
    /// must match the number of delimiter-led entries, each entry must begin with its delimiter
    /// (FirstFieldInGroupIsDelimiter), and members must be in order (ValidateUnorderedGroupFields).
    /// Nested groups are validated recursively (FR-004/FR-005).
    fn validate_groups(
        &self,
        message: &Message,
        opts: &ValidationOptions,
    ) -> Result<(), ValidationError> {
        let body: Vec<&Field> = message.body.fields().collect();
        let mut pos = 0usize;
        while let Some(f) = body.get(pos) {
            let tag = f.tag();
            if self.groups.contains_key(&tag) {
                self.validate_group(&body, &mut pos, tag, opts)?;
            } else {
                pos += 1;
            }
        }
        Ok(())
    }

    fn validate_group(
        &self,
        body: &[&Field],
        pos: &mut usize,
        count_tag: u32,
        opts: &ValidationOptions,
    ) -> Result<(), ValidationError> {
        let Some(gdef) = self.groups.get(&count_tag) else {
            *pos += 1;
            return Ok(());
        };
        let declared = body.get(*pos).and_then(|f| f.as_int().ok()).unwrap_or(-1);
        *pos += 1; // consume the count field

        let mut found = 0i64;
        while let Some(f) = body.get(*pos) {
            let tag = f.tag();
            if tag != gdef.delimiter {
                // A group member where the delimiter was expected means the entry is malformed.
                if opts.first_field_in_group_is_delimiter
                    && found < declared
                    && (gdef.members.contains(&tag) || self.groups.contains_key(&tag))
                {
                    return Err(ValidationError::session(
                        RejectReason::RepeatingGroupFieldsOutOfOrder,
                        Some(gdef.delimiter),
                        "group entry does not begin with its delimiter",
                    ));
                }
                break; // end of this group
            }
            found += 1;
            *pos += 1; // consume delimiter

            let mut last_idx = 0usize; // the delimiter is members[0]
            while let Some(mf) = body.get(*pos) {
                let t = mf.tag();
                if t == gdef.delimiter {
                    break; // next entry
                }
                if !gdef.members.contains(&t) {
                    break; // field belongs to an enclosing scope
                }
                let idx = gdef
                    .members
                    .iter()
                    .position(|&m| m == t)
                    .unwrap_or(usize::MAX);
                if opts.validate_unordered_group_fields && idx < last_idx {
                    return Err(ValidationError::session(
                        RejectReason::RepeatingGroupFieldsOutOfOrder,
                        Some(t),
                        "repeating-group fields out of order",
                    ));
                }
                last_idx = idx;
                if self.groups.contains_key(&t) {
                    self.validate_group(body, pos, t, opts)?; // nested group
                } else {
                    *pos += 1;
                }
            }
        }

        if declared != found {
            return Err(ValidationError::session(
                RejectReason::IncorrectNumInGroupCount,
                Some(count_tag),
                "NoXxx count does not match the number of group entries",
            ));
        }
        Ok(())
    }
}

fn present(message: &Message, tag: u32) -> bool {
    message.header.get(tag).is_some()
        || message.body.get(tag).is_some()
        || message.trailer.get(tag).is_some()
}

//! The normalized dictionary model and validation types.

use std::collections::{BTreeMap, BTreeSet};

use truefix_core::Field;

/// A FIX field's value type (drives format validation).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FieldType {
    /// Integer.
    Int,
    /// Length.
    Length,
    /// Sequence number.
    SeqNum,
    /// Repeating-group count.
    NumInGroup,
    /// Float.
    Float,
    /// Price.
    Price,
    /// Quantity.
    Qty,
    /// Amount.
    Amt,
    /// Percentage.
    Percentage,
    /// Single character.
    Char,
    /// Boolean (`Y`/`N`).
    Boolean,
    /// String.
    String,
    /// Binary data.
    Data,
    /// UTC timestamp.
    UtcTimestamp,
    /// UTC time-only.
    UtcTimeOnly,
    /// UTC date-only.
    UtcDateOnly,
    /// Month-year.
    MonthYear,
}

impl FieldType {
    /// Parse a normalized type token (e.g. `"PRICE"`).
    pub fn parse(token: &str) -> Option<Self> {
        Some(match token {
            "INT" => Self::Int,
            "LENGTH" => Self::Length,
            "SEQNUM" => Self::SeqNum,
            "NUMINGROUP" => Self::NumInGroup,
            "FLOAT" => Self::Float,
            "PRICE" => Self::Price,
            "QTY" => Self::Qty,
            "AMT" => Self::Amt,
            "PERCENTAGE" => Self::Percentage,
            "CHAR" => Self::Char,
            "BOOLEAN" => Self::Boolean,
            "STRING" => Self::String,
            "DATA" => Self::Data,
            "UTCTIMESTAMP" => Self::UtcTimestamp,
            "UTCTIMEONLY" => Self::UtcTimeOnly,
            "UTCDATEONLY" => Self::UtcDateOnly,
            "MONTHYEAR" => Self::MonthYear,
            _ => return None,
        })
    }

    /// Whether `field`'s value is well-formed for this type.
    pub fn value_ok(self, field: &Field) -> bool {
        match self {
            Self::Int | Self::Length | Self::SeqNum | Self::NumInGroup => field.as_int().is_ok(),
            Self::Float | Self::Price | Self::Qty | Self::Amt | Self::Percentage => {
                field.as_decimal().is_ok()
            }
            Self::Char => field.as_char().is_ok(),
            Self::Boolean => field.as_bool().is_ok(),
            Self::UtcTimestamp => field.as_utc_timestamp().is_ok(),
            // String/Data/date/time-only are accepted as-is at this layer.
            _ => true,
        }
    }
}

/// A field definition.
#[derive(Debug, Clone)]
pub struct FieldDef {
    /// Tag number.
    pub tag: u32,
    /// Field name.
    pub name: String,
    /// Value type.
    pub field_type: FieldType,
    /// Allowed enumerated values (empty = any value of the type).
    pub values: Vec<String>,
}

impl FieldDef {
    /// Whether `value` is allowed (always true when the field is not enumerated).
    pub fn allows(&self, value: &str) -> bool {
        self.values.is_empty() || self.values.iter().any(|v| v == value)
    }
}

/// A message definition: required and optional field tags.
#[derive(Debug, Clone)]
pub struct MessageDef {
    /// MsgType value (e.g. `"D"`).
    pub msg_type: String,
    /// Message name (e.g. `"NewOrderSingle"`).
    pub name: String,
    /// Required body field tags.
    pub required: Vec<u32>,
    /// Optional body field tags.
    pub optional: Vec<u32>,
    /// All valid body tags, including transitively-nested repeating-group member tags. Computed by
    /// the parser once groups are known; used for the "tag defined for message type" check.
    pub member_tags: BTreeSet<u32>,
}

impl MessageDef {
    /// Whether `tag` is a directly required or optional body field of this message.
    pub fn allows_tag(&self, tag: u32) -> bool {
        self.required.contains(&tag) || self.optional.contains(&tag)
    }

    /// Whether `tag` is valid anywhere in this message's body, including within its repeating
    /// groups (transitively).
    pub fn contains_member(&self, tag: u32) -> bool {
        self.allows_tag(tag) || self.member_tags.contains(&tag)
    }
}

/// A parsed FIX data dictionary for one version.
#[derive(Debug, Clone)]
pub struct DataDictionary {
    pub(crate) version: String,
    pub(crate) fields: BTreeMap<u32, FieldDef>,
    pub(crate) field_by_name: BTreeMap<String, u32>,
    pub(crate) messages: BTreeMap<String, MessageDef>,
    pub(crate) header: BTreeSet<u32>,
    pub(crate) trailer: BTreeSet<u32>,
    pub(crate) groups: BTreeMap<u32, GroupDef>,
    pub(crate) hash: u64,
}

impl DataDictionary {
    /// The dictionary version (BeginString).
    pub fn version(&self) -> &str {
        &self.version
    }

    /// The content hash of the source this dictionary was parsed from.
    pub fn hash(&self) -> u64 {
        self.hash
    }

    /// Look up a field definition by tag.
    pub fn field(&self, tag: u32) -> Option<&FieldDef> {
        self.fields.get(&tag)
    }

    /// Look up a field's tag by name.
    pub fn field_by_name(&self, name: &str) -> Option<u32> {
        self.field_by_name.get(name).copied()
    }

    /// Look up a message definition by MsgType.
    pub fn message(&self, msg_type: &str) -> Option<&MessageDef> {
        self.messages.get(msg_type)
    }

    /// Look up a repeating-group definition by its NoXxx count tag.
    pub fn group(&self, count_tag: u32) -> Option<&GroupDef> {
        self.groups.get(&count_tag)
    }

    /// Whether `tag` is a repeating-group count tag in this dictionary.
    pub fn is_group_count(&self, tag: u32) -> bool {
        self.groups.contains_key(&tag)
    }

    /// Whether `tag` is a header field.
    pub fn is_header(&self, tag: u32) -> bool {
        self.header.contains(&tag)
    }

    /// Whether `tag` is a trailer field.
    pub fn is_trailer(&self, tag: u32) -> bool {
        self.trailer.contains(&tag)
    }

    /// Number of defined fields.
    pub fn field_count(&self) -> usize {
        self.fields.len()
    }

    /// Number of defined messages.
    pub fn message_count(&self) -> usize {
        self.messages.len()
    }
}

/// FIX SessionRejectReason / business reject reason for a validation failure.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RejectReason {
    /// Tag number is not defined in the dictionary (0).
    InvalidTagNumber,
    /// A required tag is missing (1).
    RequiredTagMissing,
    /// Tag not defined for this message type (2).
    TagNotDefinedForMessageType,
    /// Undefined tag (3).
    UndefinedTag,
    /// Tag specified without a value (4).
    TagSpecifiedWithoutValue,
    /// Value is incorrect / out of range for the field (5).
    ValueIsIncorrect,
    /// Incorrect data format for the value (6).
    IncorrectDataFormat,
    /// Invalid or unsupported MsgType (11).
    InvalidMsgType,
    /// A tag appears more than once outside a repeating group (13).
    TagAppearsMoreThanOnce,
    /// A tag is out of the required order â€” e.g. the standard header's first fields, or
    /// header/body/trailer sectioning (14).
    TagOutOfRequiredOrder,
    /// A repeating group's fields are out of order / delimiter missing (15).
    RepeatingGroupFieldsOutOfOrder,
    /// The NoXxx count does not match the number of group entries (16).
    IncorrectNumInGroupCount,
}

impl RejectReason {
    /// The numeric SessionRejectReason (tag 373) code.
    pub fn code(self) -> u32 {
        match self {
            Self::InvalidTagNumber => 0,
            Self::RequiredTagMissing => 1,
            Self::TagNotDefinedForMessageType => 2,
            Self::UndefinedTag => 3,
            Self::TagSpecifiedWithoutValue => 4,
            Self::ValueIsIncorrect => 5,
            Self::IncorrectDataFormat => 6,
            Self::InvalidMsgType => 11,
            Self::TagAppearsMoreThanOnce => 13,
            Self::TagOutOfRequiredOrder => 14,
            Self::RepeatingGroupFieldsOutOfOrder => 15,
            Self::IncorrectNumInGroupCount => 16,
        }
    }
}

/// A repeating-group definition: the NoXxx count tag, the entry delimiter (first field), and the
/// ordered member tags (a member that is itself a count tag denotes a nested group).
#[derive(Debug, Clone)]
pub struct GroupDef {
    /// The NoXxx count tag (e.g. 453 NoPartyIDs).
    pub count_tag: u32,
    /// The delimiter tag that starts each entry (e.g. 448 PartyID).
    pub delimiter: u32,
    /// The ordered member tags of each entry (including the delimiter first).
    pub members: Vec<u32>,
}

/// A validation failure.
#[derive(Debug, Clone, PartialEq, Eq, thiserror::Error)]
#[error("{reason:?} (tag {ref_tag:?}): {text}")]
pub struct ValidationError {
    /// Why the message was rejected.
    pub reason: RejectReason,
    /// The offending tag, if applicable.
    pub ref_tag: Option<u32>,
    /// `true` => business-level reject; `false` => session-level reject.
    pub business: bool,
    /// Human-readable detail.
    pub text: String,
}

impl ValidationError {
    pub(crate) fn session(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: false,
            text: text.to_owned(),
        }
    }

    pub(crate) fn business(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: true,
            text: text.to_owned(),
        }
    }
}

/// Which validation checks to apply (maps to the FIX `Validate*` config toggles).
#[derive(Debug, Clone, Copy)]
pub struct ValidationOptions {
    /// Reject fields present with an empty value.
    pub validate_fields_have_values: bool,
    /// Validate user-defined fields (tags â‰¥ 5000) rather than skipping them.
    pub validate_user_defined_fields: bool,
    /// Permit fields not defined for the message type / dictionary.
    pub allow_unknown_msg_fields: bool,
    /// Check that required fields are present.
    pub check_required_fields: bool,
    /// Check field value formats and enumerations.
    pub check_field_types: bool,
    /// Validate repeating-group structure (count matches entries; delimiter; ordering).
    pub check_groups: bool,
    /// Require each group entry to begin with its delimiter (FirstFieldInGroupIsDelimiter).
    pub first_field_in_group_is_delimiter: bool,
    /// Reject out-of-order fields within a group entry (ValidateUnorderedGroupFields).
    pub validate_unordered_group_fields: bool,
    /// Reject a tag that appears more than once outside a repeating group.
    pub check_repeated_tags: bool,
}

impl Default for ValidationOptions {
    fn default() -> Self {
        Self {
            validate_fields_have_values: true,
            validate_user_defined_fields: false,
            allow_unknown_msg_fields: false,
            check_required_fields: true,
            check_field_types: true,
            check_groups: true,
            first_field_in_group_is_delimiter: true,
            validate_unordered_group_fields: true,
            check_repeated_tags: true,
        }
    }
}

//! Build-time codegen (dual-track, Constitution Principle IV).
//!
//! Reads the same normalized dictionary sources the runtime loads and generates, per version:
//! a content hash (the runtime asserts its parsed hash equals this, proving both tracks derive
//! from one source), MsgType constants (`<version>_msgs`, unchanged from earlier stages), and â€”
//! for feature 002/US6 â€” strongly-typed per-message structs (thin wrappers over
//! `truefix_core::Message`), field-value enums, repeating-group entry structs, and a
//! `crack_<version>` dispatcher for typed MessageCracker-style dispatch (FR-020/021/022).
//!
//! Typed structs wrap the same generic `Message`/`FieldMap` the runtime codec produces, so
//! encode/decode is always byte-identical with the generic path (FR-021) â€” there is no separate
//! wire representation to keep in sync.

use std::collections::BTreeMap;
use std::env;
use std::fmt::Write as _;
use std::fs;
use std::path::Path;

fn fnv1a(bytes: &[u8]) -> u64 {
    let mut hash: u64 = 0xcbf2_9ce4_8422_2325;
    for &b in bytes {
        hash ^= u64::from(b);
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

/// A field definition as read from the normalized dictionary source.
struct FieldDef {
    name: String,
    ty: String,
    /// `(raw value, optional label)` â€” label comes from an optional `Value=Label` token.
    values: Vec<(String, Option<String>)>,
}

/// A repeating-group definition.
#[allow(dead_code)] // `delimiter` is parsed for completeness; codegen doesn't need it directly.
struct GroupDef {
    name: String,
    delimiter: u32,
    members: Vec<u32>,
}

/// A message definition, in declaration order.
struct MessageDef {
    msg_type: String,
    name: String,
    required: Vec<u32>,
    optional: Vec<u32>,
}

/// The whole parsed dictionary (fields/groups/messages only â€” codegen doesn't need
/// header/trailer classification, which the runtime `DataDictionary` already provides).
struct Dict {
    fields: BTreeMap<u32, FieldDef>,
    groups: BTreeMap<u32, GroupDef>,
    messages: Vec<MessageDef>,
}

fn parse_dict(text: &str) -> Dict {
    let mut fields = BTreeMap::new();
    let mut groups = BTreeMap::new();
    let mut messages = Vec::new();

    for raw in text.lines() {
        let line = match raw.find('#') {
            Some(i) => raw.split_at(i).0,
            None => raw,
        }
        .trim();
        if line.is_empty() {
            continue;
        }
        let mut tokens = line.split_whitespace();
        match tokens.next() {
            Some("field") => {
                let Some(tag) = tokens.next().and_then(|t| t.parse::<u32>().ok()) else {
                    continue;
                };
                let Some(name) = tokens.next() else { continue };
                let Some(ty) = tokens.next() else { continue };
                let values = tokens
                    .map(|tok| match tok.split_once('=') {
                        Some((v, l)) => (v.to_owned(), Some(l.to_owned())),
                        None => (tok.to_owned(), None),
                    })
                    .collect();
                fields.insert(
                    tag,
                    FieldDef {
                        name: name.to_owned(),
                        ty: ty.to_owned(),
                        values,
                    },
                );
            }
            Some("group") => {
                let Some(count_tag) = tokens.next().and_then(|t| t.parse::<u32>().ok()) else {
                    continue;
                };
                let Some(name) = tokens.next() else { continue };
                let Some(delimiter) = tokens.next().and_then(|t| t.parse::<u32>().ok()) else {
                    continue;
                };
                let members: Vec<u32> = tokens
                    .next()
                    .map(|list| list.split(',').filter_map(|s| s.parse().ok()).collect())
                    .unwrap_or_default();
                groups.insert(
                    count_tag,
                    GroupDef {
                        name: name.to_owned(),
                        delimiter,
                        members,
                    },
                );
            }
            Some("message") => {
                let Some(msg_type) = tokens.next() else {
                    continue;
                };
                let Some(name) = tokens.next() else { continue };
                let mut required = Vec::new();
                let mut optional = Vec::new();
                for tok in tokens {
                    if let Some(list) = tok.strip_prefix("req:") {
                        required = list.split(',').filter_map(|s| s.parse().ok()).collect();
                    } else if let Some(list) = tok.strip_prefix("opt:") {
                        optional = list.split(',').filter_map(|s| s.parse().ok()).collect();
                    }
                }
                messages.push(MessageDef {
                    msg_type: msg_type.to_owned(),
                    name: name.to_owned(),
                    required,
                    optional,
                });
            }
            _ => {}
        }
    }

    Dict {
        fields,
        groups,
        messages,
    }
}

/// Convert a FIX PascalCase field/message name (e.g. `ClOrdID`, `NoPartyIDs`) to snake_case,
/// treating runs of uppercase letters as acronyms and keeping a trailing bare `s` (plural) glued
/// to a 2-letter acronym (`NoPartyIDs` -> `no_party_ids`, not `no_party_i_ds`).
fn snake_case(name: &str) -> String {
    let chars: Vec<char> = name.chars().collect();
    let mut out = String::with_capacity(name.len() + 4);
    for (i, &c) in chars.iter().enumerate() {
        if i > 0 && c.is_ascii_uppercase() {
            let prev_upper = chars.get(i - 1).is_some_and(|p| p.is_ascii_uppercase());
            if !prev_upper {
                out.push('_');
            } else {
                // End of a >=2-letter acronym run, if followed by a lowercase letter: the
                // trailing letters normally start a new word, *unless* the run up to here is
                // exactly 2 letters and what follows is a bare plural `s` (e.g. `IDs`).
                let next_lower = chars.get(i + 1).is_some_and(|n| n.is_ascii_lowercase());
                if next_lower {
                    let run_len_here = {
                        let mut n = 1;
                        let mut j = i;
                        while j > 0 && chars[j - 1].is_ascii_uppercase() {
                            n += 1;
                            j -= 1;
                        }
                        n
                    };
                    let is_bare_plural_s = chars.get(i + 1) == Some(&'s')
                        && chars.get(i + 2).is_none_or(|n| !n.is_alphabetic());
                    if !(run_len_here == 2 && is_bare_plural_s) {
                        out.push('_');
                    }
                }
            }
        }
        out.push(c.to_ascii_lowercase());
    }
    if out.chars().next().is_some_and(|c| c.is_ascii_digit()) {
        out.insert(0, 'f');
    }
    match out.as_str() {
        "type" | "ref" | "self" | "move" | "in" | "fn" | "struct" | "enum" | "match" | "for" => {
            out.push('_');
        }
        _ => {}
    }
    out
}

/// Rust type + `Field` accessor/constructor names for a normalized field type.
struct TypeMapping {
    /// Rust type returned by the getter (borrowed forms use `'_`).
    rust_ty: &'static str,
    /// `Field` method that converts the raw value (e.g. `as_str`).
    getter: &'static str,
    /// Whether the getter returns a borrowed `&str` (needs `.map(str::to_owned)` avoided; kept
    /// simple by returning owned/Copy types except for STRING-like fields).
    borrowed_str: bool,
}

fn type_mapping(ty: &str) -> TypeMapping {
    match ty {
        "INT" | "LENGTH" | "SEQNUM" | "NUMINGROUP" => TypeMapping {
            rust_ty: "i64",
            getter: "as_int",
            borrowed_str: false,
        },
        "FLOAT" | "PRICE" | "QTY" | "AMT" | "PERCENTAGE" => TypeMapping {
            rust_ty: "rust_decimal::Decimal",
            getter: "as_decimal",
            borrowed_str: false,
        },
        "CHAR" => TypeMapping {
            rust_ty: "char",
            getter: "as_char",
            borrowed_str: false,
        },
        "BOOLEAN" => TypeMapping {
            rust_ty: "bool",
            getter: "as_bool",
            borrowed_str: false,
        },
        "UTCTIMESTAMP" => TypeMapping {
            rust_ty: "time::OffsetDateTime",
            getter: "as_utc_timestamp",
            borrowed_str: false,
        },
        // STRING, DATA, UTCTIMEONLY, UTCDATEONLY, MONTHYEAR, and anything unrecognized: treat as
        // a raw string (safe default; still round-trips byte-exactly).
        _ => TypeMapping {
            rust_ty: "&str",
            getter: "as_str",
            borrowed_str: true,
        },
    }
}

/// Emit a field-value enum (e.g. `pub enum Side { Buy, Sell, ... }`) if `field` declares labeled
/// enum values; returns the enum's Rust name if one was emitted.
fn emit_field_enum(code: &mut String, field: &FieldDef) -> Option<String> {
    let labeled: Vec<(&str, &str)> = field
        .values
        .iter()
        .filter_map(|(v, l)| l.as_deref().map(|l| (v.as_str(), l)))
        .collect();
    if labeled.is_empty() {
        return None;
    }
    let enum_name = field.name.clone();
    let _ = writeln!(code, "/// Enumerated values for {}.", field.name);
    let _ = writeln!(code, "#[derive(Debug, Clone, Copy, PartialEq, Eq)]");
    let _ = writeln!(code, "pub enum {enum_name} {{");
    for (_, label) in &labeled {
        let _ = writeln!(code, "    /// Wire value handled in `as_str`/`parse`.");
        let _ = writeln!(code, "    {label},");
    }
    let _ = writeln!(code, "}}");
    let _ = writeln!(code, "impl {enum_name} {{");
    let _ = writeln!(code, "    /// The raw FIX wire value.");
    let _ = writeln!(code, "    pub fn as_str(self) -> &'static str {{");
    let _ = writeln!(code, "        match self {{");
    for (value, label) in &labeled {
        let _ = writeln!(code, "            Self::{label} => {value:?},");
    }
    let _ = writeln!(code, "        }}");
    let _ = writeln!(code, "    }}");
    let _ = writeln!(
        code,
        "    /// Parse a raw FIX wire value into its enum variant."
    );
    let _ = writeln!(code, "    pub fn parse(s: &str) -> Option<Self> {{");
    let _ = writeln!(code, "        match s {{");
    for (value, label) in &labeled {
        let _ = writeln!(code, "            {value:?} => Some(Self::{label}),");
    }
    let _ = writeln!(code, "            _ => None,");
    let _ = writeln!(code, "        }}");
    let _ = writeln!(code, "    }}");
    let _ = writeln!(code, "}}");
    Some(enum_name)
}

/// Emit typed get/set accessors for `tag` on a struct whose inner field-map is reached via
/// `access` (e.g. `self.0.body`).
fn emit_field_accessors(
    code: &mut String,
    dict: &Dict,
    tag: u32,
    access: &str,
    enum_names: &BTreeMap<u32, String>,
) {
    let Some(field) = dict.fields.get(&tag) else {
        return;
    };
    let ident = snake_case(&field.name);
    if let Some(enum_name) = enum_names.get(&tag) {
        let _ = writeln!(
            code,
            "    /// {} ({tag}), as its enumerated type.",
            field.name
        );
        let _ = writeln!(
            code,
            "    pub fn {ident}(&self) -> Option<{enum_name}> {{ self.{access}.get({tag}).and_then(|f| f.as_str().ok()).and_then({enum_name}::parse) }}"
        );
        let _ = writeln!(
            code,
            "    /// Set {} ({tag}) from its enumerated type.",
            field.name
        );
        let _ = writeln!(
            code,
            "    pub fn set_{ident}(&mut self, v: {enum_name}) -> &mut Self {{ self.{access}.set(truefix_core::Field::string({tag}, v.as_str())); self }}"
        );
        return;
    }
    let mapping = type_mapping(&field.ty);
    let _ = writeln!(code, "    /// {} ({tag}).", field.name);
    if mapping.borrowed_str {
        let _ = writeln!(
            code,
            "    pub fn {ident}(&self) -> Option<&str> {{ self.{access}.get({tag}).and_then(|f| f.{}().ok()) }}",
            mapping.getter
        );
        let _ = writeln!(code, "    /// Set {} ({tag}).", field.name);
        let _ = writeln!(
            code,
            "    pub fn set_{ident}(&mut self, v: &str) -> &mut Self {{ self.{access}.set(truefix_core::Field::string({tag}, v)); self }}"
        );
    } else {
        let _ = writeln!(
            code,
            "    pub fn {ident}(&self) -> Option<{}> {{ self.{access}.get({tag}).and_then(|f| f.{}().ok()) }}",
            mapping.rust_ty, mapping.getter
        );
        let _ = writeln!(code, "    /// Set {} ({tag}).", field.name);
        // `OffsetDateTime`'s own `Display` is not the FIX wire format, so UTCTIMESTAMP fields use
        // the dedicated `Field::utc_timestamp` constructor instead of `.to_string()`.
        let ctor = if field.ty == "UTCTIMESTAMP" {
            format!("truefix_core::Field::utc_timestamp({tag}, v)")
        } else {
            format!("truefix_core::Field::string({tag}, &v.to_string())")
        };
        let _ = writeln!(
            code,
            "    pub fn set_{ident}(&mut self, v: {}) -> &mut Self {{ self.{access}.set({ctor}); self }}",
            mapping.rust_ty
        );
    }
}

/// Emit a typed entry struct for a repeating group (and recursively for any nested groups its
/// members reference), wrapping a `FieldMap`.
fn emit_group_structs(
    code: &mut String,
    dict: &Dict,
    count_tag: u32,
    enum_names: &BTreeMap<u32, String>,
    emitted: &mut std::collections::BTreeSet<u32>,
) {
    if !emitted.insert(count_tag) {
        return;
    }
    let Some(group) = dict.groups.get(&count_tag) else {
        return;
    };
    // Emit nested groups first so this struct can reference them.
    for &member in &group.members {
        if dict.groups.contains_key(&member) {
            emit_group_structs(code, dict, member, enum_names, emitted);
        }
    }
    let struct_name = format!("{}Entry", group.name);
    let _ = writeln!(code, "/// One entry of the {} repeating group.", group.name);
    let _ = writeln!(code, "#[derive(Debug, Clone, Default)]");
    let _ = writeln!(
        code,
        "pub struct {struct_name}(pub truefix_core::FieldMap);"
    );
    let _ = writeln!(code, "impl {struct_name} {{");
    let _ = writeln!(code, "    /// A new, empty entry.");
    let _ = writeln!(code, "    pub fn new() -> Self {{ Self::default() }}");
    for &member in &group.members {
        if let Some(nested) = dict.groups.get(&member) {
            let nested_struct = format!("{}Entry", nested.name);
            let ident = snake_case(&nested.name);
            let _ = writeln!(code, "    /// Nested {} group entries.", nested.name);
            let _ = writeln!(
                code,
                "    pub fn {ident}(&self) -> Vec<{nested_struct}> {{ self.0.group({member}).map(|es| es.iter().cloned().map({nested_struct}).collect()).unwrap_or_default() }}"
            );
            let _ = writeln!(
                code,
                "    /// Set the nested {} group entries.",
                nested.name
            );
            let _ = writeln!(
                code,
                "    pub fn set_{ident}(&mut self, entries: Vec<{nested_struct}>) -> &mut Self {{ let mut g = truefix_core::Group::new({member}); for e in entries {{ g.add_entry(e.0); }} self.0.add_group(g); self }}"
            );
        } else {
            emit_field_accessors(code, dict, member, "0", enum_names);
        }
    }
    let _ = writeln!(code, "}}");
    let _ = writeln!(code, "impl From<truefix_core::FieldMap> for {struct_name} {{ fn from(m: truefix_core::FieldMap) -> Self {{ Self(m) }} }}");
}

fn emit_version(code: &mut String, name: &str, bytes: &[u8]) {
    let hash = fnv1a(bytes);
    let _ = writeln!(code, "/// Content hash of the {name} dictionary source.");
    let _ = writeln!(code, "pub const {name}_DICT_HASH: u64 = {hash};");

    let text = String::from_utf8_lossy(bytes);
    let dict = parse_dict(&text);

    // --- MsgType constants (unchanged from earlier stages; dual_track.rs depends on this). ---
    let msgs_module = format!("{}_msgs", name.to_lowercase());
    let _ = writeln!(
        code,
        "/// Generated MsgType constants for the {name} dictionary."
    );
    let _ = writeln!(code, "pub mod {msgs_module} {{");
    for m in &dict.messages {
        let ident = m.name.to_uppercase();
        let _ = writeln!(code, "    /// MsgType for {}.", m.name);
        let _ = writeln!(code, "    pub const {ident}: &str = {:?};", m.msg_type);
    }
    let _ = writeln!(code, "}}");

    // --- Typed messages, field enums, group structs, and a MessageCracker dispatcher (US6). ---
    let module = name.to_lowercase();
    let _ = writeln!(
        code,
        "/// Strongly-typed per-message structs, field-value enums, group entries, and a\n\
         /// `crack_{module}` dispatcher for the {name} dictionary (FR-020/021/022)."
    );
    let _ = writeln!(code, "pub mod {module} {{");
    let _ = writeln!(code, "    #![allow(clippy::needless_lifetimes)]");
    let _ = writeln!(code, "    use truefix_core::Message;");

    // Field-value enums: one per field that carries labeled enum values, referenced by any message.
    let mut enum_names: BTreeMap<u32, String> = BTreeMap::new();
    let mut used_tags: std::collections::BTreeSet<u32> = std::collections::BTreeSet::new();
    for m in &dict.messages {
        for &t in m.required.iter().chain(m.optional.iter()) {
            used_tags.insert(t);
        }
    }
    for &tag in &used_tags {
        if let Some(field) = dict.fields.get(&tag) {
            if let Some(enum_name) = emit_field_enum(code, field) {
                enum_names.insert(tag, enum_name);
            }
        }
    }

    // Repeating-group entry structs referenced by any message.
    let mut emitted_groups = std::collections::BTreeSet::new();
    for &tag in &used_tags {
        if dict.groups.contains_key(&tag) {
            emit_group_structs(code, &dict, tag, &enum_names, &mut emitted_groups);
        }
    }

    // Per-message typed structs.
    for m in &dict.messages {
        let struct_name = m.name.clone();
        let _ = writeln!(
            code,
            "/// Typed {name} {} (MsgType={:?}).",
            m.name, m.msg_type
        );
        let _ = writeln!(code, "#[derive(Debug, Clone)]");
        let _ = writeln!(code, "pub struct {struct_name}(pub Message);");
        let _ = writeln!(code, "impl {struct_name} {{");
        let _ = writeln!(code, "    /// A new {} with MsgType stamped.", m.name);
        let _ = writeln!(code, "    pub fn new() -> Self {{");
        let _ = writeln!(code, "        let mut m = Message::new();");
        let _ = writeln!(
            code,
            "        m.header.set(truefix_core::Field::string(35, {:?}));",
            m.msg_type
        );
        let _ = writeln!(code, "        Self(m)");
        let _ = writeln!(code, "    }}");
        for &tag in m.required.iter().chain(m.optional.iter()) {
            if let Some(group) = dict.groups.get(&tag) {
                let entry_struct = format!("{}Entry", group.name);
                let ident = snake_case(&group.name);
                let _ = writeln!(code, "    /// {} group entries.", group.name);
                let _ = writeln!(
                    code,
                    "    pub fn {ident}(&self) -> Vec<{entry_struct}> {{ self.0.body.group({tag}).map(|es| es.iter().cloned().map({entry_struct}).collect()).unwrap_or_default() }}"
                );
                let _ = writeln!(code, "    /// Set the {} group entries.", group.name);
                let _ = writeln!(
                    code,
                    "    pub fn set_{ident}(&mut self, entries: Vec<{entry_struct}>) -> &mut Self {{ let mut g = truefix_core::Group::new({tag}); for e in entries {{ g.add_entry(e.0); }} self.0.body.add_group(g); self }}"
                );
            } else {
                emit_field_accessors(code, &dict, tag, "0.body", &enum_names);
            }
        }
        let _ = writeln!(
            code,
            "    /// Encode to wire bytes (byte-identical with the generic codec path)."
        );
        let _ = writeln!(
            code,
            "    pub fn encode(&self) -> Vec<u8> {{ self.0.encode() }}"
        );
        let _ = writeln!(code, "}}");
        let _ = writeln!(
            code,
            "impl Default for {struct_name} {{ fn default() -> Self {{ Self::new() }} }}"
        );
        let _ = writeln!(
            code,
            "impl From<Message> for {struct_name} {{ fn from(m: Message) -> Self {{ Self(m) }} }}"
        );
        let _ = writeln!(code, "impl From<{struct_name}> for Message {{ fn from(t: {struct_name}) -> Self {{ t.0 }} }}");
    }

    // The per-version typed handler trait + dispatcher (MessageCracker-style; FR-022).
    let handler_trait = format!("{}MessageHandler", name);
    let _ = writeln!(
        code,
        "/// A typed per-message handler for {name}; default methods are no-ops."
    );
    let _ = writeln!(code, "#[allow(unused_variables)]");
    let _ = writeln!(code, "pub trait {handler_trait} {{");
    for m in &dict.messages {
        let method = format!("on_{}", snake_case(&m.name));
        let _ = writeln!(code, "    /// Called for an inbound {} ({name}).", m.name);
        let _ = writeln!(code, "    fn {method}(&mut self, msg: &{}) {{}}", m.name);
    }
    let _ = writeln!(code, "}}");
    let _ = writeln!(
        code,
        "/// Dispatch `message` to the {handler_trait} method matching its MsgType, if `message`'s\n\
         /// BeginString is {:?}. Returns whether a handler method was invoked (FR-022).",
        version_begin_string(name)
    );
    let _ = writeln!(
        code,
        "pub fn crack_{module}(message: &Message, handler: &mut impl {handler_trait}) -> bool {{"
    );
    let _ = writeln!(
        code,
        "    if message.begin_string() != Some({:?}) {{ return false; }}",
        version_begin_string(name)
    );
    let _ = writeln!(code, "    match message.msg_type() {{");
    for m in &dict.messages {
        let method = format!("on_{}", snake_case(&m.name));
        let _ = writeln!(
            code,
            "        Some({:?}) => {{ handler.{method}(&{}(message.clone())); true }}",
            m.msg_type, m.name
        );
    }
    let _ = writeln!(code, "        _ => false,");
    let _ = writeln!(code, "    }}");
    let _ = writeln!(code, "}}");

    let _ = writeln!(code, "}}"); // close module
}

/// The BeginString a version's messages carry (FIXT.1.1-transported FIX 5.0.x app messages still
/// carry `FIXT.1.1` on the wire; this only affects `crack_*`'s guard, not accessor generation).
fn version_begin_string(name: &str) -> &'static str {
    match name {
        "FIX40" => "FIX.4.0",
        "FIX41" => "FIX.4.1",
        "FIX42" => "FIX.4.2",
        "FIX43" => "FIX.4.3",
        "FIX44" => "FIX.4.4",
        "FIXT11" => "FIXT.1.1",
        "FIX50" | "FIX50SP1" | "FIX50SP2" => "FIXT.1.1",
        _ => "",
    }
}

fn main() {
    let manifest = env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR");
    let out_dir = env::var("OUT_DIR").expect("OUT_DIR");
    let mut code = String::new();
    code.push_str("// @generated by build.rs from dict-src/normalized â€” do not edit.\n");

    for (name, file) in [
        ("FIX40", "FIX40.fixdict"),
        ("FIX41", "FIX41.fixdict"),
        ("FIX42", "FIX42.fixdict"),
        ("FIX43", "FIX43.fixdict"),
        ("FIX44", "FIX44.fixdict"),
        ("FIXT11", "FIXT11.fixdict"),
        ("FIX50", "FIX50.fixdict"),
        ("FIX50SP1", "FIX50SP1.fixdict"),
        ("FIX50SP2", "FIX50SP2.fixdict"),
    ] {
        let path = Path::new(&manifest).join("dict-src/normalized").join(file);
        println!("cargo:rerun-if-changed={}", path.display());
        let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {}: {e}", path.display()));
        emit_version(&mut code, name, &bytes);
    }

    let dest = Path::new(&out_dir).join("generated.rs");
    fs::write(&dest, code).unwrap_or_else(|e| panic!("write generated.rs: {e}"));
}

