    #[test]
    fn default_inherited_and_session_overrides() {
        let cfg = "\
[DEFAULT]
ConnectionType=acceptor
HeartBtInt=30

[SESSION]
BeginString=FIX.4.2
SenderCompID=SERVER

[SESSION]
BeginString=FIX.4.4
