//! Map parsed [`SessionSettings`] into runnable engine configuration (FR-013/014/015).
//!
//! Resolution is all-or-nothing: the first invalid/missing key aborts with a typed [`ConfigError`]
//! naming the key and session, so no partially-configured engine is produced.

use std::collections::BTreeMap;
use std::net::{SocketAddr, ToSocketAddrs};
use std::path::PathBuf;

use truefix_session::{Role, Schedule, SessionConfig, TimeStampPrecision};
use truefix_store::StoreConfig;

use crate::{ConfigError, SessionSettings};

/// Whether a session initiates or accepts connections.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ConnectionType {
    /// Listens for inbound connections.
    Acceptor,
    /// Connects out to a peer.
    Initiator,
}

/// A fully-resolved per-session configuration ready to start.
#[derive(Debug, Clone)]
pub struct ResolvedSession {
    /// The session-layer configuration.
    pub session: SessionConfig,
    /// Initiator or acceptor.
    pub connection: ConnectionType,
    /// The accept (bind) or connect (target) address.
    pub address: SocketAddr,
    /// The message store to build for this session.
    pub store: StoreConfig,
    /// TLS material and settings, present when `SocketUseSSL=Y` (FR-017).
    pub tls: Option<TlsSpec>,
}

/// TLS material and settings resolved from configuration (FR-017). The mechanism that consumes
/// this (building `rustls::{Server,Client}Config`) lives in `truefix-transport`, which depends on
/// this crate for the shared spec shape.
#[derive(Debug, Clone)]
pub struct TlsSpec {
    /// PEM file containing the certificate chain and private key (combined). Maps from
    /// `SocketKeyStore`.
    pub key_store_path: PathBuf,
    /// PEM file of CA certificates (trust roots) used to verify the peer. Maps from
    /// `SocketTrustStore`.
    pub trust_store_path: Option<PathBuf>,
    /// Require and verify a client certificate (mTLS; server side). Maps from `NeedClientAuth`.
    pub need_client_auth: bool,
    /// Minimum TLS protocol version to accept/offer. Maps from `EnabledProtocols`.
    pub min_version: Option<TlsVersion>,
    /// SNI server name an initiator presents. Maps from `SNIHostName` (when `UseSNI=Y`).
    pub server_name: Option<String>,
}

/// A minimum TLS protocol version (`EnabledProtocols`).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TlsVersion {
    /// TLS 1.2 (and above).
    Tls12,
    /// TLS 1.3 only.
    Tls13,
}

impl SessionSettings {
    /// Resolve every `[SESSION]` into a runnable [`ResolvedSession`] (FR-013/014). All-or-nothing:
    /// the first invalid or missing key aborts with a typed [`ConfigError`] (FR-015).
    pub fn resolve(&self) -> Result<Vec<ResolvedSession>, ConfigError> {
        self.sessions()
            .iter()
            .enumerate()
            .map(|(i, map)| resolve_one(map, i))
            .collect()
    }
}

type Map = BTreeMap<String, String>;

fn label(map: &Map, index: usize) -> String {
    match (map.get("SenderCompID"), map.get("TargetCompID")) {
        (Some(s), Some(t)) => format!("{s}->{t}"),
        _ => format!("#{index}"),
    }
}

fn required<'a>(map: &'a Map, key: &str, session: &str) -> Result<&'a str, ConfigError> {
    map.get(key)
        .map(String::as_str)
        .ok_or_else(|| ConfigError::MissingRequired {
            key: key.to_owned(),
            session: session.to_owned(),
        })
}

fn u32_key(map: &Map, key: &str, session: &str, default: u32) -> Result<u32, ConfigError> {
    match map.get(key) {
        None => Ok(default),
        Some(v) => v.parse().map_err(|_| ConfigError::InvalidValue {
            key: key.to_owned(),
            session: session.to_owned(),
            reason: format!("expected an integer, got {v:?}"),
        }),
    }
}

/// A `Y`/`N` boolean (case-insensitive); absent â†’ `default`.
fn bool_key(map: &Map, key: &str, default: bool) -> bool {
    map.get(key)
        .map(|v| v.eq_ignore_ascii_case("Y"))
        .unwrap_or(default)
}

fn f64_key(map: &Map, key: &str, session: &str, default: f64) -> Result<f64, ConfigError> {
    match map.get(key) {
        None => Ok(default),
        Some(v) => v.parse().map_err(|_| ConfigError::InvalidValue {
            key: key.to_owned(),
            session: session.to_owned(),
            reason: format!("expected a number, got {v:?}"),
        }),
    }
}

fn precision_key(
    map: &Map,
    key: &str,
    session: &str,
    default: TimeStampPrecision,
) -> Result<TimeStampPrecision, ConfigError> {
    match map.get(key).map(String::as_str) {
        None => Ok(default),
        Some("SECONDS") => Ok(TimeStampPrecision::Seconds),
        Some("MILLIS") => Ok(TimeStampPrecision::Milliseconds),
        Some("MICROS") => Ok(TimeStampPrecision::Microseconds),
        Some("NANOS") => Ok(TimeStampPrecision::Nanoseconds),
        Some(other) => Err(ConfigError::InvalidValue {
            key: key.to_owned(),
            session: session.to_owned(),
            reason: format!("expected SECONDS/MILLIS/MICROS/NANOS, got {other:?}"),
        }),
    }
}

fn resolve_one(map: &Map, index: usize) -> Result<ResolvedSession, ConfigError> {
    let session = label(map, index);
    let begin_string = required(map, "BeginString", &session)?.to_owned();
    let sender = required(map, "SenderCompID", &session)?.to_owned();
    let target = required(map, "TargetCompID", &session)?.to_owned();

    let (connection, role) = match required(map, "ConnectionType", &session)?
        .to_ascii_lowercase()
        .as_str()
    {
        "acceptor" => (ConnectionType::Acceptor, Role::Acceptor),
        "initiator" => (ConnectionType::Initiator, Role::Initiator),
        other => {
            return Err(ConfigError::UnknownConnectionType {
                session,
                value: other.to_owned(),
            })
        }
    };

    let mut cfg = SessionConfig::new(begin_string, sender, target, role);
    cfg.heartbeat_interval = u32_key(map, "HeartBtInt", &session, 30)?;
    cfg.reset_on_logon = bool_key(map, "ResetOnLogon", cfg.reset_on_logon);
    cfg.reset_on_logout = bool_key(map, "ResetOnLogout", false);
    cfg.reset_on_disconnect = bool_key(map, "ResetOnDisconnect", false);
    cfg.persist_messages = bool_key(map, "PersistMessages", true);
    cfg.check_latency = bool_key(map, "CheckLatency", true);
    cfg.max_latency = u32_key(map, "MaxLatency", &session, 120)?;
    cfg.logon_timeout = u32_key(map, "LogonTimeout", &session, 10)?;
    cfg.logout_timeout = u32_key(map, "LogoutTimeout", &session, 10)?;
    cfg.reconnect_interval = u32_key(map, "ReconnectInterval", &session, 30)?;
    cfg.resend_request_chunk_size = u32_key(map, "ResendRequestChunkSize", &session, 0)?;
    cfg.enable_last_msg_seq_num_processed = bool_key(map, "EnableLastMsgSeqNumProcessed", false);
    cfg.enable_next_expected_msg_seq_num = bool_key(map, "EnableNextExpectedMsgSeqNum", false);
    cfg.check_comp_id = bool_key(map, "CheckCompID", cfg.check_comp_id);
    cfg.reject_garbled_message = bool_key(map, "RejectGarbledMessage", cfg.reject_garbled_message);
    cfg.heartbeat_timeout_multiplier = u32_key(
        map,
        "HeartBeatTimeoutMultiplier",
        &session,
        cfg.heartbeat_timeout_multiplier,
    )?;
    cfg.test_request_delay_multiplier = f64_key(
        map,
        "TestRequestDelayMultiplier",
        &session,
        cfg.test_request_delay_multiplier,
    )?;
    cfg.timestamp_precision =
        precision_key(map, "TimeStampPrecision", &session, cfg.timestamp_precision)?;
    if bool_key(map, "NonStopSession", false) {
        cfg.schedule = Some(Schedule::non_stop());
    }

    let address = resolve_address(map, connection, &session)?;
    let store = resolve_store(map);
    let tls = resolve_tls(map, &session)?;

    Ok(ResolvedSession {
        session: cfg,
        connection,
        address,
        store,
        tls,
    })
}

/// Resolve TLS settings when `SocketUseSSL=Y` (FR-017): key/trust-store paths, mTLS, minimum
/// version, and SNI.
fn resolve_tls(map: &Map, session: &str) -> Result<Option<TlsSpec>, ConfigError> {
    if !bool_key(map, "SocketUseSSL", false) {
        return Ok(None);
    }
    let key_store_path = PathBuf::from(required(map, "SocketKeyStore", session)?);
    let trust_store_path = map.get("SocketTrustStore").map(PathBuf::from);
    let need_client_auth = bool_key(map, "NeedClientAuth", false);
    let min_version = match map.get("EnabledProtocols").map(String::as_str) {
        None => None,
        Some(v) if v.contains("1.3") && !v.contains("1.2") => Some(TlsVersion::Tls13),
        Some(_) => Some(TlsVersion::Tls12),
    };
    let server_name = if bool_key(map, "UseSNI", false) {
        Some(
            map.get("SNIHostName")
                .cloned()
                .unwrap_or_else(|| "localhost".to_owned()),
        )
    } else {
        None
    };
    Ok(Some(TlsSpec {
        key_store_path,
        trust_store_path,
        need_client_auth,
        min_version,
        server_name,
    }))
}

fn resolve_address(
    map: &Map,
    connection: ConnectionType,
    session: &str,
) -> Result<SocketAddr, ConfigError> {
    let (host, port_key) = match connection {
        ConnectionType::Acceptor => (
            map.get("SocketAcceptAddress")
                .map(String::as_str)
                .unwrap_or("0.0.0.0"),
            "SocketAcceptPort",
        ),
        ConnectionType::Initiator => (
            required(map, "SocketConnectHost", session)?,
            "SocketConnectHost/Port",
        ),
    };
    let port_str = match connection {
        ConnectionType::Acceptor => required(map, "SocketAcceptPort", session)?,
        ConnectionType::Initiator => required(map, "SocketConnectPort", session)?,
    };
    let port: u16 = port_str.parse().map_err(|_| ConfigError::InvalidValue {
        key: port_key.to_owned(),
        session: session.to_owned(),
        reason: format!("expected a port number, got {port_str:?}"),
    })?;
    (host, port)
        .to_socket_addrs()
        .ok()
        .and_then(|mut it| it.next())
        .ok_or_else(|| ConfigError::InvalidValue {
            key: port_key.to_owned(),
            session: session.to_owned(),
            reason: format!("could not resolve address {host}:{port}"),
        })
}

fn resolve_store(map: &Map) -> StoreConfig {
    match map.get("FileStorePath") {
        Some(dir) => StoreConfig::File {
            dir: PathBuf::from(dir),
        },
        None => StoreConfig::Memory,
    }
}

//! SQL-backed message store (JDBC-equivalent), behind the `sql` feature.

use std::str::FromStr;

use async_trait::async_trait;
use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use sqlx::Row;

use crate::{MessageStore, StoreError};

fn backend<E: std::fmt::Display>(e: E) -> StoreError {
    StoreError::Backend(e.to_string())
}

/// A SQL-backed store using `sqlx` (SQLite). Maps the QuickFIX/J JDBC store tables
/// (sequence numbers + sent messages) to a relational schema.
pub struct SqlStore {
    pool: SqlitePool,
}

impl SqlStore {
    /// Connect to `url` (e.g. `sqlite://truefix.db` or `sqlite::memory:`) and ensure the schema.
    pub async fn connect(url: &str) -> Result<Self, StoreError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(backend)?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts).await.map_err(backend)?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS seqnums (\
             id INTEGER PRIMARY KEY CHECK (id = 0), sender INTEGER NOT NULL, target INTEGER NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;
        sqlx::query("INSERT OR IGNORE INTO seqnums (id, sender, target) VALUES (0, 1, 1)")
            .execute(&pool)
            .await
            .map_err(backend)?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS messages (seq INTEGER PRIMARY KEY, data BLOB NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(backend)?;

        Ok(Self { pool })
    }

    async fn get_seq(&self, column: &str) -> Result<u64, StoreError> {
        let sql = format!("SELECT {column} FROM seqnums WHERE id = 0");
        let row = sqlx::query(&sql)
            .fetch_one(&self.pool)
            .await
            .map_err(backend)?;
        let value: i64 = row.try_get(column).map_err(backend)?;
        Ok(value as u64)
    }

    async fn set_seq(&self, column: &str, seq: u64) -> Result<(), StoreError> {
        let sql = format!("UPDATE seqnums SET {column} = ? WHERE id = 0");
        sqlx::query(&sql)
            .bind(seq as i64)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

#[async_trait]
impl MessageStore for SqlStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("sender").await
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        self.get_seq("target").await
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("sender", seq).await
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.set_seq("target", seq).await
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        sqlx::query("INSERT OR REPLACE INTO messages (seq, data) VALUES (?, ?)")
            .bind(seq as i64)
            .bind(message)
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        let rows =
            sqlx::query("SELECT seq, data FROM messages WHERE seq BETWEEN ? AND ? ORDER BY seq")
                .bind(begin as i64)
                .bind(end as i64)
                .fetch_all(&self.pool)
                .await
                .map_err(backend)?;
        let mut out = Vec::with_capacity(rows.len());
        for row in rows {
            let seq: i64 = row.try_get("seq").map_err(backend)?;
            let data: Vec<u8> = row.try_get("data").map_err(backend)?;
            out.push((seq as u64, data));
        }
        Ok(out)
    }
    async fn reset(&self) -> Result<(), StoreError> {
        sqlx::query("DELETE FROM messages")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        sqlx::query("UPDATE seqnums SET sender = 1, target = 1 WHERE id = 0")
            .execute(&self.pool)
            .await
            .map_err(backend)?;
        Ok(())
    }
}

//! File-backed message stores.
//!
//! Layout in the store directory:
//! - `seqnums` â€” text: sender sequence on line 1, target sequence on line 2.
//! - `body` â€” append log of records: `seq(8 LE) | len(4 LE) | bytes`.
//!
//! On open, the body log is replayed into memory; a truncated/corrupt trailing record is
//! tolerated (recovered up to the last complete record) and flagged, supporting
//! ForceResendWhenCorruptedStore (T060).

use std::collections::BTreeMap;
use std::fs;
use std::io::{ErrorKind, Write};
use std::path::{Path, PathBuf};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Mutex;

use async_trait::async_trait;

use crate::memory::State;
use crate::{MessageStore, StoreError};

fn io_err(e: std::io::Error) -> StoreError {
    StoreError::Io(e.to_string())
}

/// A durable, file-backed message store.
pub struct FileStore {
    seq_path: PathBuf,
    body_path: PathBuf,
    state: Mutex<State>,
    corrupted: AtomicBool,
}

impl FileStore {
    /// Open (creating if needed) a file store in `dir`.
    pub fn open(dir: &Path) -> Result<Self, StoreError> {
        fs::create_dir_all(dir).map_err(io_err)?;
        let seq_path = dir.join("seqnums");
        let body_path = dir.join("body");
        let (sender, target) = load_seqnums(&seq_path)?;
        let (messages, corrupted) = load_body(&body_path)?;
        Ok(Self {
            seq_path,
            body_path,
            state: Mutex::new(State {
                sender,
                target,
                messages,
            }),
            corrupted: AtomicBool::new(corrupted),
        })
    }

    /// Whether a corrupt trailing record was detected and recovered on open.
    pub fn was_corrupted(&self) -> bool {
        self.corrupted.load(Ordering::SeqCst)
    }

    fn lock(&self) -> Result<std::sync::MutexGuard<'_, State>, StoreError> {
        self.state
            .lock()
            .map_err(|_| StoreError::Backend("poisoned lock".into()))
    }

    fn write_seqnums(&self, sender: u64, target: u64) -> Result<(), StoreError> {
        fs::write(&self.seq_path, format!("{sender}\n{target}\n")).map_err(io_err)
    }
}

#[async_trait]
impl MessageStore for FileStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        Ok(self.lock()?.sender)
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        Ok(self.lock()?.target)
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        let target = {
            let mut s = self.lock()?;
            s.sender = seq;
            s.target
        };
        self.write_seqnums(seq, target)
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        let sender = {
            let mut s = self.lock()?;
            s.target = seq;
            s.sender
        };
        self.write_seqnums(sender, seq)
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        append_record(&self.body_path, seq, message)?;
        self.lock()?.messages.insert(seq, message.to_vec());
        Ok(())
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        Ok(self.lock()?.range(begin, end))
    }
    async fn reset(&self) -> Result<(), StoreError> {
        {
            let mut s = self.lock()?;
            *s = State::default();
        }
        fs::write(&self.body_path, []).map_err(io_err)?;
        self.corrupted.store(false, Ordering::SeqCst);
        self.write_seqnums(1, 1)
    }
}

/// A file-backed store that also caches messages in memory for fast resend.
///
/// In Stage S5 it shares [`FileStore`]'s durable implementation; the cached variant is where
/// write-batching optimizations will live.
pub struct CachedFileStore(FileStore);

impl CachedFileStore {
    /// Open (creating if needed) a cached file store in `dir`.
    pub fn open(dir: &Path) -> Result<Self, StoreError> {
        Ok(Self(FileStore::open(dir)?))
    }

    /// Whether a corrupt trailing record was detected and recovered on open.
    pub fn was_corrupted(&self) -> bool {
        self.0.was_corrupted()
    }
}

#[async_trait]
impl MessageStore for CachedFileStore {
    async fn next_sender_seq(&self) -> Result<u64, StoreError> {
        self.0.next_sender_seq().await
    }
    async fn next_target_seq(&self) -> Result<u64, StoreError> {
        self.0.next_target_seq().await
    }
    async fn set_next_sender_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.0.set_next_sender_seq(seq).await
    }
    async fn set_next_target_seq(&self, seq: u64) -> Result<(), StoreError> {
        self.0.set_next_target_seq(seq).await
    }
    async fn save(&self, seq: u64, message: &[u8]) -> Result<(), StoreError> {
        self.0.save(seq, message).await
    }
    async fn get(&self, begin: u64, end: u64) -> Result<Vec<(u64, Vec<u8>)>, StoreError> {
        self.0.get(begin, end).await
    }
    async fn reset(&self) -> Result<(), StoreError> {
        self.0.reset().await
    }
}

fn load_seqnums(path: &Path) -> Result<(u64, u64), StoreError> {
    match fs::read_to_string(path) {
        Ok(s) => {
            let mut lines = s.lines();
            let sender = lines
                .next()
                .and_then(|l| l.trim().parse().ok())
                .unwrap_or(1);
            let target = lines
                .next()
                .and_then(|l| l.trim().parse().ok())
                .unwrap_or(1);
            Ok((sender, target))
        }
        Err(e) if e.kind() == ErrorKind::NotFound => Ok((1, 1)),
        Err(e) => Err(io_err(e)),
    }
}

fn load_body(path: &Path) -> Result<(BTreeMap<u64, Vec<u8>>, bool), StoreError> {
    match fs::read(path) {
        Ok(data) => Ok(parse_records(&data)),
        Err(e) if e.kind() == ErrorKind::NotFound => Ok((BTreeMap::new(), false)),
        Err(e) => Err(io_err(e)),
    }
}

/// Replay records; returns the message map and whether a corrupt trailing record was found.
fn parse_records(data: &[u8]) -> (BTreeMap<u64, Vec<u8>>, bool) {
    let mut map = BTreeMap::new();
    let mut pos = 0usize;
    loop {
        let Some(seq) = read_u64(data, pos) else {
            return (map, pos != data.len());
        };
        let Some(len) = read_u32(data, pos + 8) else {
            return (map, true);
        };
        let start = pos + 12;
        let Some(end) = start.checked_add(len as usize) else {
            return (map, true);
        };
        let Some(bytes) = data.get(start..end) else {
            return (map, true);
        };
        map.insert(seq, bytes.to_vec());
        pos = end;
    }
}

fn append_record(path: &Path, seq: u64, message: &[u8]) -> Result<(), StoreError> {
    let mut f = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .map_err(io_err)?;
    f.write_all(&seq.to_le_bytes()).map_err(io_err)?;
    let len = u32::try_from(message.len())
        .map_err(|_| StoreError::Backend("message too large".into()))?;
    f.write_all(&len.to_le_bytes()).map_err(io_err)?;
    f.write_all(message).map_err(io_err)?;
    Ok(())
}

fn read_u64(data: &[u8], pos: usize) -> Option<u64> {
    let end = pos.checked_add(8)?;
    let bytes: [u8; 8] = data.get(pos..end)?.try_into().ok()?;
    Some(u64::from_le_bytes(bytes))
}

fn read_u32(data: &[u8], pos: usize) -> Option<u32> {
    let end = pos.checked_add(4)?;
    let bytes: [u8; 4] = data.get(pos..end)?.try_into().ok()?;
    Some(u32::from_le_bytes(bytes))
}

//! `truefix-log` â€” pluggable FIX logging with message/event stream separation (FR-H2).
//!
//! The [`Log`] trait separates **message** logging (inbound/outbound wire messages) from
//! **event** logging (session lifecycle, errors). Implementations: [`ScreenLog`], [`FileLog`],
//! [`TracingLog`], and [`CompositeLog`] (fan-out).
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

mod composite;
mod file;
mod screen;
#[cfg(feature = "sql")]
mod sql;
mod tracing_log;

use std::path::PathBuf;

use thiserror::Error;

pub use composite::CompositeLog;
pub use file::FileLog;
pub use screen::ScreenLog;
#[cfg(feature = "sql")]
pub use sql::SqlLog;
pub use tracing_log::TracingLog;

/// An error constructing a log.
#[derive(Debug, Error)]
pub enum LogError {
    /// An I/O error (e.g. opening a log file).
    #[error("log I/O error: {0}")]
    Io(String),
}

/// A FIX log sink. Message logging (incoming/outgoing) is kept separate from event logging.
///
/// Methods are best-effort and infallible from the caller's perspective; a sink that cannot
/// write drops the entry rather than failing the session.
pub trait Log: Send + Sync {
    /// Log an inbound wire message.
    fn on_incoming(&self, message: &str);
    /// Log an outbound wire message.
    fn on_outgoing(&self, message: &str);
    /// Log a session event.
    fn on_event(&self, text: &str);
}

/// Which log backend to construct.
#[derive(Debug, Clone)]
pub enum LogConfig {
    /// Log to stdout/stderr.
    Screen,
    /// Log to files in a directory (`messages.log` + `event.log`).
    File {
        /// Directory holding the log files.
        dir: PathBuf,
    },
    /// Log via the `tracing` facade.
    Tracing,
    /// Fan out to several logs.
    Composite(Vec<LogConfig>),
}

/// Build a boxed [`Log`] from a [`LogConfig`].
pub fn build_log(config: &LogConfig) -> Result<Box<dyn Log>, LogError> {
    Ok(match config {
        LogConfig::Screen => Box::new(ScreenLog::new()),
        LogConfig::File { dir } => Box::new(FileLog::open(dir)?),
        LogConfig::Tracing => Box::new(TracingLog::new()),
        LogConfig::Composite(parts) => {
            let mut logs: Vec<Box<dyn Log>> = Vec::with_capacity(parts.len());
            for part in parts {
                logs.push(build_log(part)?);
            }
            Box::new(CompositeLog::new(logs))
        }
    })
}

//! SQL-backed log (JDBC-equivalent), behind the `sql` feature.
//!
//! The [`Log`] trait is synchronous and infallible, while `sqlx` is async. [`SqlLog`] bridges the
//! two: each entry is pushed onto an unbounded channel (a non-blocking, sync send) and written to
//! the database by a background task.

use std::str::FromStr;

use sqlx::sqlite::{SqliteConnectOptions, SqlitePool};
use tokio::sync::mpsc;

use crate::{Log, LogError};

enum Entry {
    Message {
        direction: &'static str,
        text: String,
    },
    Event {
        text: String,
    },
}

/// A SQL-backed log writing to `log_messages` and `log_events` tables via a background task.
pub struct SqlLog {
    tx: mpsc::UnboundedSender<Entry>,
}

impl SqlLog {
    /// Connect to `url` (e.g. `sqlite://truefix-log.db`), ensure the schema, and spawn the writer.
    pub async fn connect(url: &str) -> Result<Self, LogError> {
        let opts = SqliteConnectOptions::from_str(url)
            .map_err(|e| LogError::Io(e.to_string()))?
            .create_if_missing(true);
        let pool = SqlitePool::connect_with(opts)
            .await
            .map_err(|e| LogError::Io(e.to_string()))?;

        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             direction TEXT NOT NULL, text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;
        sqlx::query(
            "CREATE TABLE IF NOT EXISTS log_events (id INTEGER PRIMARY KEY AUTOINCREMENT, \
             text TEXT NOT NULL)",
        )
        .execute(&pool)
        .await
        .map_err(|e| LogError::Io(e.to_string()))?;

        let (tx, mut rx) = mpsc::unbounded_channel::<Entry>();
        tokio::spawn(async move {
            while let Some(entry) = rx.recv().await {
                match entry {
                    Entry::Message { direction, text } => {
                        let _ =
                            sqlx::query("INSERT INTO log_messages (direction, text) VALUES (?, ?)")
                                .bind(direction)
                                .bind(text)
                                .execute(&pool)
                                .await;
                    }
                    Entry::Event { text } => {
                        let _ = sqlx::query("INSERT INTO log_events (text) VALUES (?)")
                            .bind(text)
                            .execute(&pool)
                            .await;
                    }
                }
            }
        });

        Ok(Self { tx })
    }
}

impl Log for SqlLog {
    fn on_incoming(&self, message: &str) {
        let _ = self.tx.send(Entry::Message {
            direction: "I",
            text: message.to_owned(),
        });
    }
    fn on_outgoing(&self, message: &str) {
        let _ = self.tx.send(Entry::Message {
            direction: "O",
            text: message.to_owned(),
        });
    }
    fn on_event(&self, text: &str) {
        let _ = self.tx.send(Entry::Event {
            text: text.to_owned(),
        });
    }
}

