//! The normalized dictionary model and validation types.

use std::collections::{BTreeMap, BTreeSet};

use truefix_core::Field;

/// A FIX field's value type (drives format validation).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FieldType {
    /// Integer.
    Int,
    /// Length.
    Length,
    /// Sequence number.
    SeqNum,
    /// Repeating-group count.
    NumInGroup,
    /// Float.
    Float,
    /// Price.
    Price,
    /// Quantity.
    Qty,
    /// Amount.
    Amt,
    /// Percentage.
    Percentage,
    /// Single character.
    Char,
    /// Boolean (`Y`/`N`).
    Boolean,
    /// String.
    String,
    /// Binary data.
    Data,
    /// UTC timestamp.
    UtcTimestamp,
    /// UTC time-only.
    UtcTimeOnly,
    /// UTC date-only.
    UtcDateOnly,
    /// Month-year.
    MonthYear,
}

impl FieldType {
    /// Parse a normalized type token (e.g. `"PRICE"`).
    pub fn parse(token: &str) -> Option<Self> {
        Some(match token {
            "INT" => Self::Int,
            "LENGTH" => Self::Length,
            "SEQNUM" => Self::SeqNum,
            "NUMINGROUP" => Self::NumInGroup,
            "FLOAT" => Self::Float,
            "PRICE" => Self::Price,
            "QTY" => Self::Qty,
            "AMT" => Self::Amt,
            "PERCENTAGE" => Self::Percentage,
            "CHAR" => Self::Char,
            "BOOLEAN" => Self::Boolean,
            "STRING" => Self::String,
            "DATA" => Self::Data,
            "UTCTIMESTAMP" => Self::UtcTimestamp,
            "UTCTIMEONLY" => Self::UtcTimeOnly,
            "UTCDATEONLY" => Self::UtcDateOnly,
            "MONTHYEAR" => Self::MonthYear,
            _ => return None,
        })
    }

    /// Whether `field`'s value is well-formed for this type.
    pub fn value_ok(self, field: &Field) -> bool {
        match self {
            Self::Int | Self::Length | Self::SeqNum | Self::NumInGroup => field.as_int().is_ok(),
            Self::Float | Self::Price | Self::Qty | Self::Amt | Self::Percentage => {
                field.as_decimal().is_ok()
            }
            Self::Char => field.as_char().is_ok(),
            Self::Boolean => field.as_bool().is_ok(),
            Self::UtcTimestamp => field.as_utc_timestamp().is_ok(),
            // String/Data/date/time-only are accepted as-is at this layer.
            _ => true,
        }
    }
}

/// A field definition.
#[derive(Debug, Clone)]
pub struct FieldDef {
    /// Tag number.
    pub tag: u32,
    /// Field name.
    pub name: String,
    /// Value type.
    pub field_type: FieldType,
    /// Allowed enumerated values (empty = any value of the type).
    pub values: Vec<String>,
}

impl FieldDef {
    /// Whether `value` is allowed (always true when the field is not enumerated).
    pub fn allows(&self, value: &str) -> bool {
        self.values.is_empty() || self.values.iter().any(|v| v == value)
    }
}

/// A message definition: required and optional field tags.
#[derive(Debug, Clone)]
pub struct MessageDef {
    /// MsgType value (e.g. `"D"`).
    pub msg_type: String,
    /// Message name (e.g. `"NewOrderSingle"`).
    pub name: String,
    /// Required body field tags.
    pub required: Vec<u32>,
    /// Optional body field tags.
    pub optional: Vec<u32>,
    /// All valid body tags, including transitively-nested repeating-group member tags. Computed by
    /// the parser once groups are known; used for the "tag defined for message type" check.
    pub member_tags: BTreeSet<u32>,
}

impl MessageDef {
    /// Whether `tag` is a directly required or optional body field of this message.
    pub fn allows_tag(&self, tag: u32) -> bool {
        self.required.contains(&tag) || self.optional.contains(&tag)
    }

    /// Whether `tag` is valid anywhere in this message's body, including within its repeating
    /// groups (transitively).
    pub fn contains_member(&self, tag: u32) -> bool {
        self.allows_tag(tag) || self.member_tags.contains(&tag)
    }
}

/// A parsed FIX data dictionary for one version.
#[derive(Debug, Clone)]
pub struct DataDictionary {
    pub(crate) version: String,
    pub(crate) fields: BTreeMap<u32, FieldDef>,
    pub(crate) field_by_name: BTreeMap<String, u32>,
    pub(crate) messages: BTreeMap<String, MessageDef>,
    pub(crate) header: BTreeSet<u32>,
    pub(crate) trailer: BTreeSet<u32>,
    pub(crate) groups: BTreeMap<u32, GroupDef>,
    pub(crate) hash: u64,
}

impl DataDictionary {
    /// The dictionary version (BeginString).
    pub fn version(&self) -> &str {
        &self.version
    }

    /// The content hash of the source this dictionary was parsed from.
    pub fn hash(&self) -> u64 {
        self.hash
    }

    /// Look up a field definition by tag.
    pub fn field(&self, tag: u32) -> Option<&FieldDef> {
        self.fields.get(&tag)
    }

    /// Look up a field's tag by name.
    pub fn field_by_name(&self, name: &str) -> Option<u32> {
        self.field_by_name.get(name).copied()
    }

    /// Look up a message definition by MsgType.
    pub fn message(&self, msg_type: &str) -> Option<&MessageDef> {
        self.messages.get(msg_type)
    }

    /// Look up a repeating-group definition by its NoXxx count tag.
    pub fn group(&self, count_tag: u32) -> Option<&GroupDef> {
        self.groups.get(&count_tag)
    }

    /// Whether `tag` is a repeating-group count tag in this dictionary.
    pub fn is_group_count(&self, tag: u32) -> bool {
        self.groups.contains_key(&tag)
    }

    /// Whether `tag` is a header field.
    pub fn is_header(&self, tag: u32) -> bool {
        self.header.contains(&tag)
    }

    /// Whether `tag` is a trailer field.
    pub fn is_trailer(&self, tag: u32) -> bool {
        self.trailer.contains(&tag)
    }

    /// Number of defined fields.
    pub fn field_count(&self) -> usize {
        self.fields.len()
    }

    /// Number of defined messages.
    pub fn message_count(&self) -> usize {
        self.messages.len()
    }
}

/// FIX SessionRejectReason / business reject reason for a validation failure.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RejectReason {
    /// Tag number is not defined in the dictionary (0).
    InvalidTagNumber,
    /// A required tag is missing (1).
    RequiredTagMissing,
    /// Tag not defined for this message type (2).
    TagNotDefinedForMessageType,
    /// Undefined tag (3).
    UndefinedTag,
    /// Tag specified without a value (4).
    TagSpecifiedWithoutValue,
    /// Value is incorrect / out of range for the field (5).
    ValueIsIncorrect,
    /// Incorrect data format for the value (6).
    IncorrectDataFormat,
    /// Invalid or unsupported MsgType (11).
    InvalidMsgType,
    /// A tag appears more than once outside a repeating group (13).
    TagAppearsMoreThanOnce,
    /// A tag is out of the required order â€” e.g. the standard header's first fields, or
    /// header/body/trailer sectioning (14).
    TagOutOfRequiredOrder,
    /// A repeating group's fields are out of order / delimiter missing (15).
    RepeatingGroupFieldsOutOfOrder,
    /// The NoXxx count does not match the number of group entries (16).
    IncorrectNumInGroupCount,
}

impl RejectReason {
    /// The numeric SessionRejectReason (tag 373) code.
    pub fn code(self) -> u32 {
        match self {
            Self::InvalidTagNumber => 0,
            Self::RequiredTagMissing => 1,
            Self::TagNotDefinedForMessageType => 2,
            Self::UndefinedTag => 3,
            Self::TagSpecifiedWithoutValue => 4,
            Self::ValueIsIncorrect => 5,
            Self::IncorrectDataFormat => 6,
            Self::InvalidMsgType => 11,
            Self::TagAppearsMoreThanOnce => 13,
            Self::TagOutOfRequiredOrder => 14,
            Self::RepeatingGroupFieldsOutOfOrder => 15,
            Self::IncorrectNumInGroupCount => 16,
        }
    }
}

/// A repeating-group definition: the NoXxx count tag, the entry delimiter (first field), and the
/// ordered member tags (a member that is itself a count tag denotes a nested group).
#[derive(Debug, Clone)]
pub struct GroupDef {
    /// The NoXxx count tag (e.g. 453 NoPartyIDs).
    pub count_tag: u32,
    /// The delimiter tag that starts each entry (e.g. 448 PartyID).
    pub delimiter: u32,
    /// The ordered member tags of each entry (including the delimiter first).
    pub members: Vec<u32>,
}

/// A validation failure.
#[derive(Debug, Clone, PartialEq, Eq, thiserror::Error)]
#[error("{reason:?} (tag {ref_tag:?}): {text}")]
pub struct ValidationError {
    /// Why the message was rejected.
    pub reason: RejectReason,
    /// The offending tag, if applicable.
    pub ref_tag: Option<u32>,
    /// `true` => business-level reject; `false` => session-level reject.
    pub business: bool,
    /// Human-readable detail.
    pub text: String,
}

impl ValidationError {
    pub(crate) fn session(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: false,
            text: text.to_owned(),
        }
    }

    pub(crate) fn business(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: true,
            text: text.to_owned(),
        }
    }
}

/// Which validation checks to apply (maps to the FIX `Validate*` config toggles).
#[derive(Debug, Clone, Copy)]
pub struct ValidationOptions {
    /// Reject fields present with an empty value.
    pub validate_fields_have_values: bool,
    /// Validate user-defined fields (tags â‰¥ 5000) rather than skipping them.
    pub validate_user_defined_fields: bool,
    /// Permit fields not defined for the message type / dictionary.
    pub allow_unknown_msg_fields: bool,
    /// Check that required fields are present.
    pub check_required_fields: bool,
    /// Check field value formats and enumerations.
    pub check_field_types: bool,
    /// Validate repeating-group structure (count matches entries; delimiter; ordering).
    pub check_groups: bool,
    /// Require each group entry to begin with its delimiter (FirstFieldInGroupIsDelimiter).
    pub first_field_in_group_is_delimiter: bool,
    /// Reject out-of-order fields within a group entry (ValidateUnorderedGroupFields).
    pub validate_unordered_group_fields: bool,
    /// Reject a tag that appears more than once outside a repeating group.
    pub check_repeated_tags: bool,
}

impl Default for ValidationOptions {
    fn default() -> Self {
        Self {
            validate_fields_have_values: true,
            validate_user_defined_fields: false,
            allow_unknown_msg_fields: false,
            check_required_fields: true,
            check_field_types: true,
            check_groups: true,
            first_field_in_group_is_delimiter: true,
            validate_unordered_group_fields: true,
            check_repeated_tags: true,
        }
    }
}

//! The SOH wire codec: [`encode`] and [`decode`].

mod decode;
mod encode;

pub use decode::{decode, decode_with_groups};
pub use encode::encode;

//! Decode wire bytes into a [`Message`], verifying BodyLength (tag 9) and CheckSum (tag 10).
//!
//! Decoding produces flat ordered fields (no dictionary-driven group parsing at this layer).
//! Binary length-prefixed data fields (e.g. RawDataLength/RawData) are handled so embedded
//! SOH bytes do not corrupt parsing. No path panics.

use crate::error::DecodeError;
use crate::field::Field;
use crate::field_map::FieldMap;
use crate::group::{Group, GroupSpec};
use crate::message::Message;
use crate::tags::{
    data_field_for_length, is_header, is_trailer, BEGIN_STRING, BODY_LENGTH, CHECK_SUM, SOH,
};

/// A tokenized field: tag, raw value bytes, and the byte offset where the field began.
type Token = (u32, Vec<u8>, usize);

/// Decode `input` into a [`Message`] with flat fields (no dictionary-driven group structure).
pub fn decode(input: &[u8]) -> Result<Message, DecodeError> {
    let fields = tokenize_validated(input)?;
    let mut msg = Message::new();
    for (tag, value, _) in fields {
        let field = Field::new(tag, value);
        if is_trailer(tag) {
            msg.trailer.add_field(field);
        } else if is_header(tag) {
            msg.header.add_field(field);
        } else {
            msg.body.add_field(field);
        }
    }
    Ok(msg)
}

/// Decode `input` into a [`Message`] with repeating groups structured per `spec` (FR-004). Header
/// and trailer fields stay flat; body group-count tags consume their delimiter-led entries
/// (nested groups recurse). Structure is best-effort/greedy â€” count/order validation is a separate
/// dictionary concern (see `truefix-dict`).
pub fn decode_with_groups(input: &[u8], spec: &dyn GroupSpec) -> Result<Message, DecodeError> {
    let fields = tokenize_validated(input)?;
    let mut msg = Message::new();
    let mut body: Vec<Token> = Vec::new();
    for (tag, value, off) in fields {
        if is_trailer(tag) {
            msg.trailer.add_field(Field::new(tag, value));
        } else if is_header(tag) {
            msg.header.add_field(Field::new(tag, value));
        } else {
            body.push((tag, value, off));
        }
    }
    let mut pos = 0usize;
    while let Some(tok) = body.get(pos) {
        let tag = tok.0;
        if let Some((delimiter, members)) = spec.group_of(tag) {
            let group = build_group(&body, &mut pos, spec, tag, delimiter, members);
            msg.body.add_group(group);
        } else {
            msg.body.add_field(Field::new(tag, tok.1.clone()));
            pos += 1;
        }
    }
    Ok(msg)
}

/// Consume a repeating group starting at the count token, returning the structured [`Group`].
fn build_group(
    tokens: &[Token],
    pos: &mut usize,
    spec: &dyn GroupSpec,
    count_tag: u32,
    delimiter: u32,
    members: &[u32],
) -> Group {
    *pos += 1; // consume the NoXxx count field
    let mut group = Group::new(count_tag);
    while let Some(tok) = tokens.get(*pos) {
        if tok.0 != delimiter {
            break; // no more entries
        }
        let mut entry = FieldMap::new();
        entry.add_field(Field::new(delimiter, tok.1.clone()));
        *pos += 1;
        while let Some(t) = tokens.get(*pos) {
            let tag = t.0;
            if tag == delimiter || !members.contains(&tag) {
                break;
            }
            if let Some((d2, m2)) = spec.group_of(tag) {
                let sub = build_group(tokens, pos, spec, tag, d2, m2);
                entry.add_group(sub);
            } else {
                entry.add_field(Field::new(tag, t.1.clone()));
                *pos += 1;
            }
        }
        group.add_entry(entry);
    }
    group
}

/// Tokenize `input` and verify BeginString/BodyLength/CheckSum.
fn tokenize_validated(input: &[u8]) -> Result<Vec<Token>, DecodeError> {
    if input.is_empty() {
        return Err(DecodeError::Empty);
    }

    let fields = tokenize(input)?;

    let first = fields.first().ok_or(DecodeError::Empty)?;
    if first.0 != BEGIN_STRING {
        return Err(DecodeError::MissingBeginString);
    }
    let second = fields.get(1).ok_or(DecodeError::InvalidBodyLength)?;
    if second.0 != BODY_LENGTH {
        return Err(DecodeError::InvalidBodyLength);
    }
    let declared_bl = parse_usize(&second.1).ok_or(DecodeError::InvalidBodyLength)?;

    let last = fields.last().ok_or(DecodeError::MissingChecksum)?;
    if last.0 != CHECK_SUM {
        return Err(DecodeError::MissingChecksum);
    }
    let declared_cs = parse_u32(&last.1).ok_or(DecodeError::MissingChecksum)?;

    // Body starts at the third field (just after `9=..<SOH>`) and ends just before `10=`.
    let cs_offset = last.2;
    let body_start = fields.get(2).map_or(cs_offset, |f| f.2);
    let actual_bl = cs_offset
        .checked_sub(body_start)
        .ok_or(DecodeError::InvalidBodyLength)?;
    if actual_bl != declared_bl {
        return Err(DecodeError::BodyLengthMismatch {
            declared: declared_bl,
            actual: actual_bl,
        });
    }

    let pre = input.get(..cs_offset).ok_or(DecodeError::MissingChecksum)?;
    let computed: u32 = pre.iter().map(|&b| u32::from(b)).sum::<u32>() & 0xFF;
    if computed != declared_cs {
        return Err(DecodeError::ChecksumMismatch {
            declared: declared_cs,
            computed,
        });
    }

    Ok(fields)
}

/// Split `input` into `tag=value<SOH>` tokens, honoring length-prefixed binary data fields.
fn tokenize(input: &[u8]) -> Result<Vec<Token>, DecodeError> {
    let mut tokens = Vec::new();
    let mut pos = 0usize;
    // When the previous field was a length field, this holds the exact byte length of the
    // next (data) field's value.
    let mut pending_data_len: Option<usize> = None;

    while pos < input.len() {
        let start = pos;
        let rest = input
            .get(pos..)
            .ok_or(DecodeError::Truncated { offset: start })?;

        let eq_rel = memchr(rest, b'=').ok_or(DecodeError::GarbledField {
            offset: start,
            reason: "missing '=' in field",
        })?;
        let tag_bytes = rest.get(..eq_rel).unwrap_or(&[]);
        let tag = parse_u32(tag_bytes).ok_or(DecodeError::InvalidTag { offset: start })?;
        let val_start = pos + eq_rel + 1;

        let (value, next) = if let Some(len) = pending_data_len.take() {
            let val_end = val_start
                .checked_add(len)
                .ok_or(DecodeError::GarbledField {
                    offset: start,
                    reason: "data length overflow",
                })?;
            let v = input
                .get(val_start..val_end)
                .ok_or(DecodeError::Truncated { offset: val_start })?;
            match input.get(val_end) {
                Some(&b) if b == SOH => (v.to_vec(), val_end + 1),
                _ => {
                    return Err(DecodeError::GarbledField {
                        offset: val_end,
                        reason: "data field not terminated by SOH",
                    })
                }
            }
        } else {
            let after = input
                .get(val_start..)
                .ok_or(DecodeError::Truncated { offset: val_start })?;
            let soh_rel = memchr(after, SOH).ok_or(DecodeError::GarbledField {
                offset: val_start,
                reason: "field not terminated by SOH",
            })?;
            let v = after.get(..soh_rel).unwrap_or(&[]);
            (v.to_vec(), val_start + soh_rel + 1)
        };

        if pending_data_len.is_none() && data_field_for_length(tag).is_some() {
            if let Some(len) = parse_usize(&value) {
                pending_data_len = Some(len);
            }
        }

        tokens.push((tag, value, start));
        pos = next;
    }

    Ok(tokens)
}

fn memchr(haystack: &[u8], needle: u8) -> Option<usize> {
    haystack.iter().position(|&b| b == needle)
}

fn parse_u32(bytes: &[u8]) -> Option<u32> {
    core::str::from_utf8(bytes).ok()?.parse().ok()
}

fn parse_usize(bytes: &[u8]) -> Option<usize> {
    core::str::from_utf8(bytes).ok()?.parse().ok()
}

//! `truefix-dict` â€” the dual-track FIX data dictionary.
//!
//! One normalized dictionary source feeds **both** tracks (Constitution Principle IV):
//! - the runtime [`DataDictionary`] (parsed at runtime, used by [`DataDictionary::validate`]);
//! - build-time **codegen** (`build.rs`) of per-version MsgType constants + a content hash.
//!
//! The generated `*_DICT_HASH` constants equal the runtime-parsed [`DataDictionary::hash`], which
//! proves the two tracks derive from the same source (see the `dual_track` test).
//!
//! Dictionaries are derived from the FIX Trading Community specifications; QuickFIX/J XML files are
//! not copied (Constitution Principle III).
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

