//! `truefix` â€” the engine facade.
//!
//! Re-exports the public surface of the layered crates so integrators depend on one crate.
//! Implement [`Application`] for your callbacks, build a [`SessionConfig`], and run an
//! [`Acceptor`] or [`connect_initiator`].
//!
//! Design: `specs/001-fix-engine-parity/`.
#![deny(missing_docs)]
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

pub use truefix_core::{
    self as core, decode, encode, DecodeError, Field, FieldError, FieldMap, Group, Message,
    MessageCracker, MessageFactory,
};
pub use truefix_session::{
    self as session, Action, Application, Event, Role, Session, SessionConfig, SessionId,
    SessionState,
};
pub use truefix_transport::{self as transport, connect_initiator, Acceptor, SessionHandle};

pub use truefix_config as config;
pub use truefix_dict as dict;

use std::sync::Arc;

use tokio::task::JoinHandle;

use truefix_config::{ConnectionType, SessionSettings};
use truefix_transport::{
    build_client_config, build_server_config, connect_initiator_tls, connect_initiator_with,
    Services,
};

/// An error starting the engine from configuration (FR-015).
#[derive(Debug, thiserror::Error)]
pub enum EngineError {
    /// A configuration mapping error (missing/invalid key, unknown ConnectionType).
    #[error(transparent)]
    Config(#[from] truefix_config::ConfigError),
    /// A message store could not be built.
    #[error("store: {0}")]
    Store(String),
    /// A network bind/connect failure.
    #[error("io: {0}")]
    Io(String),
    /// A TLS configuration could not be built from the session's `TlsSpec` (FR-017).
    #[error("tls: {0}")]
    Tls(String),
}

/// A running engine: the started acceptor listeners and initiator sessions (FR-013/014).
///
/// Built from a [`SessionSettings`] via [`Engine::start`]; each `[SESSION]` is routed by its
/// `ConnectionType` to an acceptor or initiator with a store built from its configuration.
pub struct Engine {
    acceptors: Vec<JoinHandle<()>>,
    initiators: Vec<SessionHandle>,
}

impl Engine {
    /// Build and start every session described by `settings`, sharing `app` across them.
    ///
    /// All-or-nothing: a configuration-resolution error returns before anything is started
    /// (FR-015). Each session gets a store built from its `FileStorePath`/store keys, and TLS
    /// (including mTLS) built from its `SocketUseSSL`/`SocketKeyStore`/... keys when
    /// `SocketUseSSL=Y` (FR-017) â€” no code-level TLS construction required.
    pub async fn start<A: Application + 'static>(
        settings: &SessionSettings,
        app: Arc<A>,
    ) -> Result<Self, EngineError> {
        let resolved = settings.resolve()?;
        let mut acceptors = Vec::new();
        let mut initiators = Vec::new();
        for rs in resolved {
            let store = truefix_store::build_store(&rs.store)
                .await
                .map_err(|e| EngineError::Store(e.to_string()))?;
            let services = Services {
                store: Some(Arc::from(store)),
                ..Services::default()
            };
            match rs.connection {
                ConnectionType::Acceptor => {
                    let mut acc =
                        Acceptor::bind_with(rs.address, rs.session, app.clone(), services)
                            .await
                            .map_err(|e| EngineError::Io(e.to_string()))?;
                    if let Some(tls) = &rs.tls {
                        let server_cfg = build_server_config(tls)
                            .map_err(|e| EngineError::Tls(e.to_string()))?;
                        acc = acc.with_tls(server_cfg);
                    }
                    acceptors.push(acc.serve());
                }
                ConnectionType::Initiator => {
                    let handle = match &rs.tls {
                        Some(tls) => {
                            let client_cfg = build_client_config(tls)
                                .map_err(|e| EngineError::Tls(e.to_string()))?;
                            let host = tls.server_name.clone().unwrap_or_default();
                            let server_name = rustls::pki_types::ServerName::try_from(host)
                                .map_err(|e| EngineError::Tls(e.to_string()))?;
                            connect_initiator_tls(
                                rs.address,
                                rs.session,
                                app.clone(),
                                services,
                                client_cfg,
                                server_name,
                            )
                            .await
                            .map_err(|e| EngineError::Io(e.to_string()))?
                        }
                        None => {
                            connect_initiator_with(rs.address, rs.session, app.clone(), services)
                                .await
                                .map_err(|e| EngineError::Io(e.to_string()))?
                        }
                    };
                    initiators.push(handle);
                }
            }
        }
        Ok(Self {
            acceptors,
            initiators,
        })
    }

    /// The started initiator session handles (for logout/join).
    pub fn initiators(&self) -> &[SessionHandle] {
        &self.initiators
    }

    /// Abort all acceptor listeners.
    pub fn shutdown(&self) {
        for acceptor in &self.acceptors {
            acceptor.abort();
        }
    }
}

//! `truefix-config` â€” QuickFIX-style `.cfg` settings parsing.
//!
//! Parses the `[DEFAULT]` / `[SESSION]` dialect: a `[DEFAULT]` section whose keys are inherited
//! by every `[SESSION]` (per-session keys override), with `${name}` variable interpolation.
//! The full Appendix A key surface and the mapping to `SessionConfig` are filled in across
//! later stages; Stage S2 provides parsing + inheritance + interpolation.
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

pub mod builder;
pub mod keys;

use std::collections::BTreeMap;

use thiserror::Error;

pub use builder::{ConnectionType, ResolvedSession, TlsSpec, TlsVersion};
pub use keys::{key_info, KeyInfo, Stance, APPENDIX_A_KEYS};

/// An error parsing a settings document.
#[derive(Debug, Clone, PartialEq, Eq, Error)]
pub enum ConfigError {
    /// A non-empty, non-comment line was not `key=value` and not a `[Section]` header.
    #[error("line {line}: expected `key=value` or `[Section]`, got {text:?}")]
    Malformed {
        /// 1-based line number.
        line: usize,
        /// The offending text.
        text: String,
    },
    /// A `${name}` reference could not be resolved.
    #[error("line {line}: unresolved variable ${{{name}}}")]
    UnresolvedVariable {
        /// 1-based line number.
        line: usize,
        /// The variable name.
        name: String,
    },
    /// A required configuration key is missing for a session (FR-015).
    #[error("session {session}: missing required key `{key}`")]
    MissingRequired {
        /// The missing key.
        key: String,
        /// The session label (SenderCompID->TargetCompID, or an index).
        session: String,
    },
    /// A recognized key has an invalid value (FR-015).
    #[error("session {session}: invalid value for `{key}`: {reason}")]
    InvalidValue {
        /// The offending key.
        key: String,
        /// The session label.
        session: String,
        /// Why the value is invalid.
        reason: String,
    },
    /// `ConnectionType` was neither `acceptor` nor `initiator` (FR-014).
    #[error("session {session}: unknown ConnectionType `{value}`")]
    UnknownConnectionType {
        /// The session label.
        session: String,
        /// The offending value.
        value: String,
    },
}

/// A parsed settings document: the `[DEFAULT]` section plus the `[SESSION]` sections (each with
/// defaults already merged in).
#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct SessionSettings {
    default: BTreeMap<String, String>,
    sessions: Vec<BTreeMap<String, String>>,
}

impl SessionSettings {
    /// Parse a settings document.
    pub fn parse(input: &str) -> Result<Self, ConfigError> {
        // `current` accumulates the raw key/values of the section being read.
        let mut default: BTreeMap<String, String> = BTreeMap::new();
        let mut sessions: Vec<BTreeMap<String, String>> = Vec::new();
        // None = no section yet; Some(true) = DEFAULT; Some(false) = a SESSION.
        let mut in_default: Option<bool> = None;
        let mut current: BTreeMap<String, String> = BTreeMap::new();

        for (idx, raw) in input.lines().enumerate() {
            let line_no = idx + 1;
            let line = strip_comment(raw).trim();
            if line.is_empty() {
                continue;
            }

            if let Some(name) = section_header(line) {
                flush_section(in_default, &mut current, &mut default, &mut sessions);
                in_default = Some(name.eq_ignore_ascii_case("DEFAULT"));
                current = BTreeMap::new();
                continue;
            }

            let (key, value) = line.split_once('=').ok_or_else(|| ConfigError::Malformed {
                line: line_no,
                text: line.to_owned(),
            })?;
            current.insert(key.trim().to_owned(), value.trim().to_owned());
        }
        flush_section(in_default, &mut current, &mut default, &mut sessions);

        // Resolve `${name}` in default first, then in each session against (default + session).
        let default = interpolate_map(&default, &default)?;
        let mut resolved_sessions = Vec::with_capacity(sessions.len());
        for session in &sessions {
            let mut merged = default.clone();
            for (k, v) in session {
                merged.insert(k.clone(), v.clone());
            }
            resolved_sessions.push(interpolate_map(&merged, &merged)?);
        }

        Ok(Self {
            default,
            sessions: resolved_sessions,
        })
    }

    /// The resolved `[DEFAULT]` section.
    pub fn default_section(&self) -> &BTreeMap<String, String> {
        &self.default
    }

    /// The resolved `[SESSION]` sections (each already merged with defaults).
    pub fn sessions(&self) -> &[BTreeMap<String, String>] {
        &self.sessions
    }
}

fn flush_section(
    in_default: Option<bool>,
    current: &mut BTreeMap<String, String>,
    default: &mut BTreeMap<String, String>,
    sessions: &mut Vec<BTreeMap<String, String>>,
) {
    match in_default {
        Some(true) => {
            for (k, v) in current.iter() {
                default.insert(k.clone(), v.clone());
            }
        }
        Some(false) if !current.is_empty() => {
            sessions.push(std::mem::take(current));
        }
        _ => {}
    }
    current.clear();
}

fn strip_comment(line: &str) -> &str {
    match line.find('#') {
        Some(idx) => line.get(..idx).unwrap_or(""),
        None => line,
    }
}

fn section_header(line: &str) -> Option<&str> {
    let inner = line.strip_prefix('[')?.strip_suffix(']')?;
    Some(inner.trim())
}

/// Interpolate `${name}` occurrences in every value of `map`, looking names up in `lookup`.
fn interpolate_map(
    map: &BTreeMap<String, String>,
    lookup: &BTreeMap<String, String>,
) -> Result<BTreeMap<String, String>, ConfigError> {
    let mut out = BTreeMap::new();
    for (k, v) in map {
        out.insert(k.clone(), interpolate_value(v, lookup)?);
    }
    Ok(out)
}

fn interpolate_value(
    value: &str,
    lookup: &BTreeMap<String, String>,
) -> Result<String, ConfigError> {
    let mut result = String::with_capacity(value.len());
    let mut rest = value;
    while let Some(start) = rest.find("${") {
        let (before, after) = rest.split_at(start);
        result.push_str(before);
        let after = after.get(2..).unwrap_or("");
        let end = after
            .find('}')
            .ok_or_else(|| ConfigError::UnresolvedVariable {
                line: 0,
                name: after.to_owned(),
            })?;
        let name = after.get(..end).unwrap_or("");
        let replacement = lookup
            .get(name)
            .ok_or_else(|| ConfigError::UnresolvedVariable {
                line: 0,
                name: name.to_owned(),
            })?;
        result.push_str(replacement);
        rest = after.get(end + 1..).unwrap_or("");
    }
    result.push_str(rest);
    Ok(result)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn default_inherited_and_session_overrides() {
        let cfg = "\
[DEFAULT]
ConnectionType=acceptor
HeartBtInt=30

[SESSION]
BeginString=FIX.4.2
SenderCompID=SERVER

[SESSION]
BeginString=FIX.4.4
