        // inherited default
        assert_eq!(s.sessions()[0].get("HeartBtInt"), Some(&"30".to_string()));
        // per-session override
        assert_eq!(s.sessions()[1].get("HeartBtInt"), Some(&"10".to_string()));
        assert_eq!(
